@router.get("/summary")
async def get_analytics_summary(
    period_days: int = Query(30, ge=1, le=365, description="Период в днях"),
    marketplace: Optional[str] = Query(
        None, description="Фильтр по маркетплейсу (ozon/wb/yandex)"
    ),
    shop_id: Optional[UUID] = Query(None, description="Фильтр по shop_id"),
    db: AsyncSession = Depends(get_db),
    current_user: TokenData = Depends(get_current_user),
):
    """Получить сводную аналитику."""
    from src.analytics.engine import AnalyticsEngine

    reviews = await _load_reviews(
        db, period_days, current_user, marketplace, shop_id=shop_id
    )
    engine = AnalyticsEngine()
    summary = engine.compute_summary(reviews=reviews, period_days=period_days)

    # Marketplace breakdown for the frontend chart
    shop_ids = await _get_user_shop_ids(db, current_user)
    if shop_id is not None and shop_id in shop_ids:
        shop_ids = [shop_id]

    cutoff = datetime.now(timezone.utc) - timedelta(days=period_days)
    mp_query = (
        select(
            Review.marketplace,
            func.count(Review.id).label("total"),
            func.avg(Review.rating).label("avg_rating"),
            func.count(
                case(
                    (Review.status.in_([ReviewStatus.SENT, ReviewStatus.APPROVED]), 1),
                )
            ).label("answered"),
        )
        .where(Review.review_date >= cutoff)
        .where(Review.shop_id.in_(shop_ids))
        .group_by(Review.marketplace)
    )
    if marketplace:
        mp_query = mp_query.where(Review.marketplace == marketplace)

    mp_result = await db.execute(mp_query)
    marketplace_stats = {}
    for row in mp_result.all():
        mp_name = (
            row[0].value
            if hasattr(row[0], "value")
            else str(row[0])
            if row[0]
            else "unknown"
        )
        marketplace_stats[mp_name] = {
            "reviews": row[1] or 0,
            "responses": row[3] or 0,
            "avg_rating": round(float(row[2]), 2) if row[2] else 0,
        }

    # Rating distribution (1-5 stars)
    rd_query = (
        select(Review.rating, func.count(Review.id).label("cnt"))
        .where(Review.review_date >= cutoff)
        .where(Review.shop_id.in_(shop_ids))
        .where(Review.rating.isnot(None))
        .group_by(Review.rating)
    )
    if marketplace:
        rd_query = rd_query.where(Review.marketplace == marketplace)
    rd_result = await db.execute(rd_query)
    rating_distribution = {str(r): 0 for r in range(1, 6)}
    for row in rd_result.all():
        if row[0] and 1 <= row[0] <= 5:
            rating_distribution[str(row[0])] = row[1] or 0

    return {
        "period_days": period_days,
        "marketplace": marketplace or "all",
        "total_reviews": summary.total_reviews,
        "total_answered": summary.total_answered,
        "response_rate": summary.response_rate,
        "avg_rating": summary.avg_rating,
        "avg_response_time_sec": summary.avg_response_time_sec,
        "sentiment": summary.sentiment_distribution,
        "top_topics": summary.top_topics,
        "urgent_count": summary.urgent_count,
        "reviews_trend_pct": summary.reviews_trend_pct,
        "rating_trend": summary.rating_trend,
        "marketplace_stats": marketplace_stats,
        "rating_distribution": rating_distribution,
    }


