import ExpandMoreIcon from '@mui/icons-material/ExpandMore'
import ExpandLessIcon from '@mui/icons-material/ExpandLess'
import ErrorOutlineIcon from '@mui/icons-material/ErrorOutline'
import WarningAmberIcon from '@mui/icons-material/WarningAmber'
import InfoOutlinedIcon from '@mui/icons-material/InfoOutlined'
import CheckCircleOutlineIcon from '@mui/icons-material/CheckCircleOutline'
import SyncIcon from '@mui/icons-material/Sync'
import MonitorHeartIcon from '@mui/icons-material/MonitorHeart'
import SmartToyIcon from '@mui/icons-material/SmartToy'
import HistoryIcon from '@mui/icons-material/History'
import StorageIcon from '@mui/icons-material/Storage'
import {
    LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip,
    ResponsiveContainer, Legend,
} from 'recharts'
import { format, parseISO, formatDistanceToNow } from 'date-fns'
import { ru } from 'date-fns/locale'
import { adminMonitoringService } from '../api/monitoringService'
import type {
    ErrorLog, SyncRun, ActivityLog, SystemStats, ErrorFilters,
    ActivityFilters, PaginatedErrors, PaginatedActivity, ErrorStats,
} from '../api/monitoringTypes'

// ─── Helpers ────────────────────────────────

function timeAgo(dateStr: string): string {
    try {
        return formatDistanceToNow(parseISO(dateStr), { addSuffix: true, locale: ru })
    } catch {
        return dateStr
    }
}

function fmtDate(dateStr: string): string {
    try {
        return format(parseISO(dateStr), 'dd.MM HH:mm:ss')
    } catch {
        return dateStr
    }
}

function fmtSeconds(seconds: number): string {
    if (seconds < 60) return `${Math.round(seconds)}с`
    if (seconds < 3600) return `${Math.round(seconds / 60)}м`
    return `${Math.round(seconds / 3600)}ч`
}

// ─── Stat Card ──────────────────────────────

function StatCard({ label, value, color = '#6366f1', icon, sub }: {
    label: string
    value: string | number
    color?: string
    icon?: React.ReactNode
    sub?: string
}) {
    return (
        <Card sx={{ bgcolor: `${color}08`, border: `1px solid ${color}22`, height: '100%' }}>
            <CardContent sx={{ py: 2, '&:last-child': { pb: 2 } }}>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 0.5 }}>
                    {icon && <Box sx={{ color, opacity: 0.8 }}>{icon}</Box>}
                    <Typography variant="caption" sx={{ color: 'text.secondary', textTransform: 'uppercase', letterSpacing: 1, fontSize: '0.7rem' }}>
                        {label}
                    </Typography>
                </Box>
                <Typography variant="h4" sx={{ fontWeight: 700, color }}>
                    {typeof value === 'number' ? value.toLocaleString() : value}
                </Typography>
                {sub && (
                    <Typography variant="caption" sx={{ color: 'text.secondary' }}>{sub}</Typography>
                )}
            </CardContent>
        </Card>
    )
}

