    const cfg: Record<string, { color: string; icon: React.ReactNode; label: string }> = {
        critical: { color: '#7f1d1d', icon: <ErrorOutlineIcon sx={{ fontSize: 14 }} />, label: 'CRITICAL' },
        error:    { color: '#ef4444', icon: <ErrorOutlineIcon sx={{ fontSize: 14 }} />, label: 'ERROR' },
        warning:  { color: '#f59e0b', icon: <WarningAmberIcon sx={{ fontSize: 14 }} />, label: 'WARNING' },
        info:     { color: '#6366f1', icon: <InfoOutlinedIcon sx={{ fontSize: 14 }} />, label: 'INFO' },
    }
    const c = cfg[level] ?? cfg.info
    return (
