@router.get("/sync-status")
async def sync_status(
    db: AsyncSession = Depends(get_db),
    admin=Depends(get_admin_user),
):
    """Статус синхронизации по всем магазинам."""
    result = await db.execute(
        select(Shop).where(Shop.is_active.is_(True)).order_by(Shop.name)
    )
    shops = result.scalars().all()

    now = datetime.now(timezone.utc)
    statuses = []

    # Единый запрос вместо N+1 — GROUP BY shop_id
    products_rows = (
        await db.execute(
            select(Product.shop_id, func.count(Product.id).label("cnt")).group_by(
                Product.shop_id
            )
        )
    ).all()
    reviews_rows = (
        await db.execute(
            select(Review.shop_id, func.count(Review.id).label("cnt")).group_by(
                Review.shop_id
            )
        )
    ).all()
    products_map: dict = {row.shop_id: row.cnt for row in products_rows}
    reviews_map: dict = {row.shop_id: row.cnt for row in reviews_rows}

    for shop in shops:
        products_count = products_map.get(shop.id, 0)
        reviews_count = reviews_map.get(shop.id, 0)

        # Время с последней синхронизации
        last_sync = shop.last_sync_at
        ago = None
        if last_sync:
            delta = now - last_sync
            if delta.total_seconds() < 3600:
                ago = f"{int(delta.total_seconds() / 60)} мин назад"
            elif delta.total_seconds() < 86400:
                ago = f"{int(delta.total_seconds() / 3600)} ч назад"
            else:
                ago = f"{delta.days} дн назад"

        statuses.append(
            {
                "shop_id": str(shop.id),
                "name": shop.name,
                "marketplace": shop.marketplace.value
                if hasattr(shop.marketplace, "value")
                else str(shop.marketplace),
                "is_active": shop.is_active,
                "products_count": products_count or 0,
                "reviews_count": reviews_count or 0,
                "last_sync_at": last_sync.isoformat() if last_sync else None,
                "last_sync_ago": ago,
            }
        )

    return {"shops": statuses, "total": len(statuses)}


